course.content:
C++ ajoute le type `std::string` pour les chaînes.

```cpp
#include <string>
std::string nom = "Ada";
int n = 5;
bool actif = true;
```

```cpp
for (int i = 1; i <= 3; i++) {
    std::cout << i << std::endl;
}
```

La syntaxe des boucles `for`/`while` est identique à celle du C.

exercises.correction:
#include <iostream>
#include <string>
int main() {
    std::string nom = "Ada";
    std::cout << "Bonjour " << nom << std::endl;
    return 0;
}

#include <iostream>
int main() {
    for (int i = 1; i <= 5; i++) {
        std::cout << i << std::endl;
    }
    return 0;
}

#include <iostream>
int main() {
    int n = 8;
    if (n % 2 == 0) std::cout << "pair" << std::endl;
    else std::cout << "impair" << std::endl;
    return 0;
}
